mapper.select:
SELECT ac.CodeID AS codeId, ac.AuthCode AS authCode, e.Name AS name, e.Position AS position, e.Department AS department, e.Role AS role, ac.Status AS status, ac.UsedBy AS usedBy, ac.UsedAt AS usedAt FROM auth_codes ac LEFT JOIN employees e ON ac.UsedBy = e.EmployeeID
AND e.Name LIKE CONCAT('%', #{name}, '%')
AND ac.Role = #{role}
AND ac.Status = #{status}
order by UsedAt DESC
